inline const Marker* getMarkers(PlaRegion r, size_t& count) {
    switch (r) {
        case PlaRegion::ObsidianFieldlands: count = OBSIDIAN_FIELDLANDS_COUNT; return OBSIDIAN_FIELDLANDS;
        case PlaRegion::CrimsonMirelands:   count = CRIMSON_MIRELANDS_COUNT;   return CRIMSON_MIRELANDS;
        case PlaRegion::CobaltCoastlands:   count = COBALT_COASTLANDS_COUNT;   return COBALT_COASTLANDS;
        case PlaRegion::CoronetHighlands:   count = CORONET_HIGHLANDS_COUNT;   return CORONET_HIGHLANDS;
        case PlaRegion::AlabasterIcelands:  count = ALABASTER_ICELANDS_COUNT;  return ALABASTER_ICELANDS;
        default: count = 0; return nullptr;
    }
}

inline int findMarker(int groupId, const Marker*& outMarker) {
    for (int r = 0; r < (int)PlaRegion::Count; r++) {
        size_t n; const Marker* ms = getMarkers((PlaRegion)r, n);
        for (size_t i = 0; i < n; i++) {
            if (ms[i].groupId == groupId) { outMarker = &ms[i]; return r; }
        }
    }
    outMarker = nullptr;
    return -1;
}

// Resolve a slot roll [0, slotTotal) to a SlotEntry for this marker.
inline const SlotEntry* resolveSlot(const Marker& m, double slotRoll) {
    if (m.slotCount == 0 || m.slotTotal == 0) return nullptr;
    double acc = 0;
    for (uint8_t i = 0; i < m.slotCount; i++) {
        acc += SLOTS[m.slotOffset + i].weight;
        if (slotRoll < acc) return &SLOTS[m.slotOffset + i];
    }
    return &SLOTS[m.slotOffset + m.slotCount - 1];
}

